import asyncio
from collections.abc import Awaitable, Callable


async def run_tasks(
    tasks: list[Callable[[], Awaitable[None]]], max_concurrent: int
) -> None:
    """Run async callables with a bounded number of concurrent invocations.

    A cancellation of this coroutine stops scheduling immediately, cancels
    every callable that was already started, and waits for it to finish. This
    gives those callables a chance to run their normal cleanup before
    cancellation is propagated to the caller.
    """
    if max_concurrent < 1:
        raise ValueError("max_concurrent must be at least 1")

    active: set[asyncio.Task[None]] = set()
    next_task = iter(tasks)
    exhausted = False

    def start_tasks() -> None:
        nonlocal exhausted
        while not exhausted and len(active) < max_concurrent:
            try:
                task = next(next_task)
            except StopIteration:
                exhausted = True
                break
            active.add(asyncio.create_task(task()))

    try:
        start_tasks()
        while active:
            done, pending = await asyncio.wait(
                active, return_when=asyncio.FIRST_COMPLETED
            )
            active = pending

            # Retrieve every result before propagating an exception so that
            # no completed task is left with an unobserved exception.
            error: BaseException | None = None
            for task in done:
                try:
                    task.result()
                except BaseException as exc:
                    if error is None:
                        error = exc
            if error is not None:
                raise error

            start_tasks()
    except asyncio.CancelledError:
        # Cancel only tasks whose callables were invoked. Awaiting them lets
        # their finally blocks complete; queued callables are never invoked.
        if active:
            for task in active:
                task.cancel()
            await asyncio.gather(*active, return_exceptions=True)
        raise
